      res.status(500).json({ error: "Failed to update control plan row" });
    }
  });

  // Equipment Library API
  app.get("/api/equipment", async (req, res) => {
    try {
      const equipment = await storage.getAllEquipment();
      res.json(equipment);
    } catch (error) {
